  // Narrow the type and handle each case
}

console.log(processData("  hello  "));
console.log(processData(3.14159));
console.log(processData(true));
console.log(processData(null));

exercises.solution:
function processData(data: unknown): string {
  if (typeof data === "string") {
    return data.trim().toUpperCase();
  }
  if (typeof data === "number") {
    return data.toFixed(2);
  }
  if (typeof data === "boolean") {
    return data ? "yes" : "no";
  }
  return "unknown type";
}

console.log(processData("  hello  "));
console.log(processData(3.14159));
console.log(processData(true));
console.log(processData(null));

exercises.starterCode:
// Define LogLevel type and formatLog function


console.log(formatLog("info", "Server started"));
console.log(formatLog("warn", "Disk space low"));
console.log(formatLog("error", "Connection failed"));

exercises.solution:
type LogLevel = "info" | "warn" | "error";

function formatLog(level: LogLevel, message: string): string {
  switch (level) {
    case "info":
      return `[INFO] ${message}`;
    case "warn":
      return `[WARN] ${message}`;
    case "error":
      return `[ERROR] ${message}`;
    default:
      const exhaustive: never = level;
      return exhaustive;
  }
}

console.log(formatLog("info", "Server started"));
console.log(formatLog("warn", "Disk space low"));
console.log(formatLog("error", "Connection failed"));
